"use strict";const e=require("../common/vendor.js");exports.request=t=>new Promise((o,s)=>{e.index.request({url:"https://www.xiaojiaoyaya.cn/index.php/api/"+t.url,method:t.method||"GET",data:t.data||{},header:{"Content-Type":"application/json;charset=UTF-8"},success:t=>{const{data:n}=t;200===t.statusCode?o(n):(e.index.showToast({title:n.msg||"请求失败",icon:"none"}),s(n))},fail:t=>{e.index.showToast({title:"网络异常，请稍后重试",icon:"none"}),s(t)}})});
